1	import { describe, it, expect } from "vitest";
2	import { quote, claim } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  describe("quote — single item base premiums (R1)", () => {
6	    it("amulet alone → base premium 60 G (before fee, no other modifiers)", () => {
7	      const result = quote({ yearsWithMHPCO: 0 }, [{ type: "amulet" }], { followUp: false });
8	      expect(result.basePremium).toBe(60);
9	    });
10	    it.todo("sword alone → base premium 100 G");
11	    it.todo("staff alone → base premium 80 G");
12	    it.todo("potion alone → base premium 40 G");
13	    it.todo("a single rune → base premium 25 G");
14	    it.todo("empty item list → premium 5 G (processing fee only)");
15	  });
16	
17	  describe("quote — component building blocks (R2, R3)", () => {
18	    it.todo("2 runes → base premium 50 G (below block size, 2×25)");
19	    it.todo("3 runes → base premium 60 G (block of exactly 3 applies)");
20	    it.todo("4 runes → base premium 100 G (no block — block requires exactly 3, 4×25)");
21	    it.todo("7 runes → base premium 175 G (no block — 7×25)");
22	    it.todo("2 runes + 1 moonstone → base premium 75 G (no block: different types, 3×25)");
23	    it.todo("3 runes + 3 moonstones → base premium 120 G (two separate blocks, 60 + 60)");
24	  });
25	
26	  describe("quote — premium modifiers and scope (R4, R5)", () => {
27	    it.todo("cursed sword adds 50% to the item base premium → 150 G base+surcharge (before policy modifiers and fee)");
28	    it.todo("sword with enchantment exactly 5 → high-enchantment 30% surcharge applies");
29	    it.todo("sword with enchantment 4 → no high-enchantment surcharge");
30	    it.todo("customer with exactly 2 years → 20% loyalty discount applies");
31	    it.todo("policy with cursed sword (100) + plain amulet (60) → 210 G before policy-wide modifiers and fee (cursed surcharge 50 = 50% of sword base only)");
32	  });
33	
34	  describe("quote — integration examples (R4, R5, R8)", () => {
35	    it.todo("newcomer (0 yrs), cursed sword (steel, ench 3) → premium 165 G (100 base + 50 curse + 10 first-insurance + 5 fee)");
36	    it.todo("long-standing customer (3 yrs), second quote, cursed sword (steel, ench 7) → premium 160 G (100 + 50 curse + 30 high-ench − 20 loyalty + 10 first-ins − 15 follow-up + 5 fee)");
37	    it.todo("premium that computes to 197.5 G → rounded up to 198 G (MHPCO favor)");
38	  });
39	
40	  describe("claim — standard reimbursement and clauses (R7)", () => {
41	    it.todo("regular sword (steel, ench 3), damage 500 G → payout 400 G (500 − 100 deductible)");
42	    it.todo("rune (insurance value 250 G), damage 200 G → payout 100 G (200 − 100, no special clause)");
43	    it.todo("dragon-material sword, enchantment exactly 8, damage 1000 G → payout 400 G (50% clause then deductible: 500 − 100)");
44	    it.todo("dragon-material sword, enchantment 5, damage 800 G → payout 700 G (dragon full reimbursement then deductible: 800 − 100)");
45	    it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (high-ench 50% then deductible: 500 − 100)");
46	    it.todo("dragon-material sword, enchantment 9, damage 1000 G → payout 400 G (50% rule wins over dragon, then deductible)");
47	    it.todo("dragon attack: sword damaged 500 G + amulet damaged 300 G → payout 600 G (100 G deductible per damaged item)");
48	    it.todo("payout that computes to 350.5 G → rounded down to 350 G (MHPCO favor)");
49	  });
50	
51	  describe("claim — caps and exhaustion (R7)", () => {
52	    it.todo("sword + amulet → insurance sum 1600 G, cap 3200 G (2× sum of insurance values)");
53	    it.todo("cursed sword (value 1000, premium 165) → cap 2000 G (based on unmodified insurance value)");
54	    it.todo("sword + 3 runes (block) → insurance sum 1750 G (1000 + 3×250; block discount affects premium only)");
55	    it.todo("sword (cap 2000), two successive 1500 G claims → first payout 1400 G (remaining cap 600), second payout 600 G (remaining cap 0)");
56	    it.todo("two swords → insurance sum 2000 G, cap 4000 G");
57	    it.todo("two swords both damaged (two sword damage entries) → each treated as separate damage with its own 100 G deductible");
58	  });
59	});
60	
61	describe("MHPCO Claim Office — CLI (src/cli.ts via stdin/stdout)", () => {
62	  it.todo("CLI reads a JSON scenario from stdin and writes {results:[...]} with a premium integer for a quote step");
63	  it.todo("CLI writes payout and remainingCap integers for a claim step result, in step order");
64	  it.todo("CLI exits with non-zero status and writes error to stderr (no results on stdout) when a quote item has an unknown type (e.g. broomstick)");
65	  it.todo("CLI exits with non-zero status when a claim references an item not in the policy (e.g. amulet damaged when only a sword is insured)");
66	  it.todo("CLI exits with non-zero status when a damage entry has a negative amount (e.g. -200)");
67	  it.todo("CLI exits with non-zero status when damages contain more entries of a type than the policy covers (two sword damages, one sword insured)");
68	});
